export const algoChallenges = [
  { id: 3101, lang: "Algo", diff: "medium", title: "Segment Tree Range Sum", concepts: "Segment Tree, Range Query", problem: "Build a segment tree that supports range sum queries and point updates in O(log n).", why: "Segment trees appear in competitive programming and systems with range-query needs (leaderboards, analytics).", examples: "arr=[1,3,5,7,9,11], query(1,3)=>15, update(1,2)=>arr=[1,2,5,7,9,11]", testInputs: "query(0,5) => 35 after update", explanation: "Build: each node stores sum of its range. Query: split into O(log n) nodes. Update: propagate up." },
  { id: 3102, lang: "Algo", diff: "medium", title: "Fenwick Tree (BIT)", concepts: "Binary Indexed Tree, Prefix Sum", problem: "Implement a Fenwick Tree with point update and prefix sum query in O(log n).", why: "BITs are simpler than segment trees for prefix sums. Asked at Google, Meta.", examples: "update(i, delta), prefixSum(i)", testInputs: "arr=[2,1,1,3,2,3,4,5,6,7,8,9] => prefixSum(5)=12", explanation: "Use i & (-i) trick to find parent/children. Update: i += i & (-i). Query: i -= i & (-i)." },
  { id: 3103, lang: "Algo", diff: "medium", title: "Dijkstra's Shortest Path", concepts: "Graph, Min-Heap, Greedy", problem: "Find shortest path from a source to all nodes in a weighted graph using Dijkstra's algorithm.", why: "Core graph algorithm. Used in routing, maps, network optimization.", examples: "Graph: {0:[1,4],[2,1]}, {1:[3,1]}, {2:[1,2],[3,5]} => dist from 0: [0,3,1,4]", testInputs: "Negative weights => undefined behavior (not supported)", explanation: "Use a min-heap. Relax edges greedily. O((V+E)log V) with priority queue." },
  { id: 3104, lang: "Algo", diff: "medium", title: "Bellman-Ford Algorithm", concepts: "Graph, Dynamic Programming, Negative Cycles", problem: "Find shortest paths from source, handling negative weights. Detect negative cycles.", why: "Handles negative edges unlike Dijkstra. Essential for financial arbitrage detection, network routing.", examples: "Graph with negative edge: relax all edges V-1 times", testInputs: "Negative cycle present => return 'cycle detected'", explanation: "Relax all E edges V-1 times. If still relaxable on Vth pass, negative cycle exists." },
  { id: 3105, lang: "Algo", diff: "medium", title: "Floyd-Warshall All Pairs", concepts: "Graph, 2D DP, All-Pairs Shortest Path", problem: "Find shortest paths between every pair of vertices. Handle negative edges (no negative cycles).", why: "Used when you need distances between all pairs — transit networks, social graph distances.", examples: "3-node graph => 3x3 distance matrix", testInputs: "dist[i][i] = 0, dist[i][j] = min via all intermediates", explanation: "dp[i][j] = min(dp[i][j], dp[i][k] + dp[k][j]) for each intermediate k." },
  { id: 3106, lang: "Algo", diff: "medium", title: "Topological Sort (Kahn's)", concepts: "Graph, BFS, In-Degree", problem: "Topologically sort a DAG using Kahn's algorithm (BFS-based). Detect cycles.", why: "Used in build systems, package dependency resolution, task scheduling.", examples: "Edges: 5->2, 5->0, 4->0, 4->1, 2->3, 3->1 => valid topological order", testInputs: "Graph with cycle => return empty/signal cycle", explanation: "Compute in-degrees. Queue nodes with 0 in-degree. Process, reduce neighbors' in-degree, enqueue when 0." },
  { id: 3107, lang: "Algo", diff: "medium", title: "Union-Find (Disjoint Set Union)", concepts: "DSU, Path Compression, Union by Rank", problem: "Implement Union-Find with path compression and union by rank. Support connected components query.", why: "Used in Kruskal's MST, cycle detection, network connectivity, image segmentation.", examples: "union(0,1), union(1,2), find(0)==find(2) => true", testInputs: "find after multiple unions => correct root", explanation: "find: recurse with path compression (node.parent = find(parent)). union: attach smaller rank to larger." },
  { id: 3108, lang: "Algo", diff: "medium", title: "Kruskal's Minimum Spanning Tree", concepts: "Graph, Union-Find, Greedy", problem: "Find the minimum spanning tree of a weighted undirected graph using Kruskal's algorithm.", why: "MST is used in network design, clustering, approximation algorithms.", examples: "Weighted edges sorted, greedily add if no cycle => MST with total weight", testInputs: "Disconnected graph => forest of MSTs", explanation: "Sort edges by weight. Use DSU to check cycles. Add edge if endpoints in different sets." },
  { id: 3109, lang: "Algo", diff: "medium", title: "Prim's Minimum Spanning Tree", concepts: "Graph, Min-Heap, Greedy", problem: "Find MST starting from an arbitrary node, always expanding by the minimum weight edge.", why: "Alternative to Kruskal's, performs better on dense graphs.", examples: "Start from node 0, greedily add min-weight adjacent edge", testInputs: "All equal weights => valid spanning tree", explanation: "Use min-heap of (weight, node). Mark visited. Add all edges of visited nodes to heap." },
  { id: 3110, lang: "Algo", diff: "medium", title: "A* Search Algorithm", concepts: "Graph, Heuristic, Priority Queue", problem: "Implement A* pathfinding on a grid with obstacles. Use Manhattan distance as heuristic.", why: "A* is the gold standard for game AI pathfinding and robotics navigation.", examples: "5x5 grid, start=(0,0), end=(4,4), obstacles present => shortest path", testInputs: "No path exists => return empty", explanation: "f(n) = g(n) + h(n). Priority queue ordered by f. Only valid (non-obstacle, in-bounds) neighbors." },
  { id: 3111, lang: "Algo", diff: "medium", title: "KMP String Search", concepts: "String, Pattern Matching, Failure Function", problem: "Implement KMP for O(n+m) pattern matching. Build the failure function (LPS array).", why: "Efficient string search. KMP is asked in interviews to test understanding of prefix-suffix overlap.", examples: "text='AABAACAADAABAABA', pattern='AABA' => found at [0, 9, 12]", testInputs: "No match => empty list", explanation: "Build LPS: lps[i] = length of longest proper prefix that is also suffix. Use to avoid re-matching." },
  { id: 3112, lang: "Algo", diff: "medium", title: "Rabin-Karp Rolling Hash", concepts: "String, Hashing, Rolling Hash", problem: "Implement Rabin-Karp for pattern matching. Explain rolling hash and collision handling.", why: "Rolling hash is widely used for plagiarism detection, substring search, and fingerprinting.", examples: "Find all occurrences of pattern in text using hash comparison", testInputs: "Handle hash collision with actual string comparison", explanation: "hash(s[i+1..i+m]) = (hash - s[i]*h^(m-1)) * base + s[i+m]. Verify on hash match." },
  { id: 3113, lang: "Algo", diff: "medium", title: "Trie with Wildcard Search", concepts: "Trie, DFS, Backtracking", problem: "Extend a Trie to support wildcard '.' character that matches any single letter.", why: "Wildcard search in dictionaries, autocomplete with fuzzy matching.", examples: "Insert 'bad', 'dad'. search('.ad') => true", testInputs: "search('b..') with 3-char words => true/false", explanation: "Normal search for char match. For '.', recursively try all children at that node." },
  { id: 3114, lang: "Algo", diff: "medium", title: "Dutch National Flag (3-Way Partition)", concepts: "Three-Way Partition, In-Place", problem: "Sort an array of 0s, 1s, and 2s in a single pass with O(1) space.", why: "Classic Dijkstra problem. Tests in-place partitioning without auxiliary storage.", examples: "Input: [2,0,2,1,1,0] => Output: [0,0,1,1,2,2]", testInputs: "All same values => unchanged order", explanation: "Maintain lo, mid, hi pointers. Swap based on value at mid: 0->front, 2->back, 1->advance mid." },
  { id: 3115, lang: "Algo", diff: "medium", title: "Quickselect (kth Smallest)", concepts: "Divide & Conquer, Partition", problem: "Find the kth smallest element in an unsorted array in average O(n) using quickselect.", why: "More efficient than sorting for selection. Used in order statistics, percentile computation.", examples: "arr=[3,2,1,5,6,4], k=2 => 2", testInputs: "k=1 => minimum. k=n => maximum", explanation: "Partition around pivot. If pivot is k-1th, return it. Else recurse into correct partition only." },
  { id: 3116, lang: "Algo", diff: "medium", title: "Morris Inorder Traversal", concepts: "Tree, O(1) Space, Threaded Binary Tree", problem: "Traverse a binary tree inorder using O(1) extra space (no stack, no recursion).", why: "Demonstrates deep understanding of tree structure. O(1) space is impressive in interviews.", examples: "Tree [1,null,2,3] => inorder [1,3,2] without stack", testInputs: "Single node => return that node value", explanation: "Find inorder predecessor. If no right child, point it to current. Restore tree structure on second visit." },
  { id: 3117, lang: "Algo", diff: "medium", title: "Count Islands with BFS vs DFS", concepts: "Graph, BFS, DFS, Grid", problem: "Compare BFS and DFS for counting islands. Implement both. Analyze time/space tradeoffs.", why: "Tests ability to identify and compare traversal strategies for grid problems.", examples: "Grid with mixed 1s and 0s => count distinct islands", testInputs: "All 1s => 1 island. All 0s => 0 islands", explanation: "DFS: call stack grows with island size. BFS: queue grows with frontier. Both O(n*m)." },
  { id: 3118, lang: "Algo", diff: "hard", title: "Tarjan's SCC Algorithm", concepts: "Graph, DFS, Strongly Connected Components", problem: "Find all strongly connected components in a directed graph using Tarjan's algorithm.", why: "SCC is used in compiler optimization, deadlock detection, and dependency analysis.", examples: "Directed graph with cycles => groups of mutually reachable nodes", testInputs: "DAG => each node is its own SCC", explanation: "DFS with discovery time and low-link values. Use stack. Pop SCC when node is root of SCC (low==disc)." },
  { id: 3119, lang: "Algo", diff: "hard", title: "Articulation Points and Bridges", concepts: "Graph, DFS, Cut Vertices", problem: "Find all articulation points (cut vertices) and bridges in an undirected graph.", why: "Network reliability analysis. Any node/edge whose removal disconnects the graph is critical.", examples: "Graph: 0-1-2-3 with 1-3 => vertex 1 is articulation point", testInputs: "Complete graph => no articulation points", explanation: "DFS with disc[] and low[]. If low[child] >= disc[u], u is AP. If low[child] > disc[u], edge is bridge." },
  { id: 3120, lang: "Algo", diff: "hard", title: "Max Flow (Edmonds-Karp)", concepts: "Graph, BFS, Augmenting Paths", problem: "Find the maximum flow in a directed graph from source to sink using Edmonds-Karp (BFS-based Ford-Fulkerson).", why: "Used in network routing, bipartite matching, project selection problems.", examples: "Source=0, Sink=5. Find max flow through capacity graph.", testInputs: "No path from source to sink => max flow = 0", explanation: "BFS to find shortest augmenting path. Augment. Update residual graph. Repeat until no path." },
  { id: 3121, lang: "Algo", diff: "hard", title: "Bipartite Matching", concepts: "Graph, Matching, Augmenting Path", problem: "Find maximum bipartite matching. Explain use in assignment problems.", why: "Job assignment, stable marriage, scheduling. Classical combinatorial optimization.", examples: "Workers and tasks bipartite graph => max matching", testInputs: "Unequal sets => partial matching", explanation: "For each unmatched left node, do DFS to find augmenting path. Flip matched/unmatched edges." },
  { id: 3122, lang: "Algo", diff: "hard", title: "Convex Hull (Graham Scan)", concepts: "Geometry, Sorting, Stack", problem: "Find the convex hull of a set of 2D points using Graham Scan in O(n log n).", why: "Computational geometry appears in graphics, robotics, GIS. Tests sorting + stack usage.", examples: "Points: [(0,0),(1,1),(2,2),(0,2),(2,0)] => hull: [(0,0),(2,0),(2,2),(0,2)]", testInputs: "All collinear points => hull is the two endpoints", explanation: "Sort by polar angle from lowest point. Scan: pop stack if not left turn. O(n log n) for sort." },
  { id: 3123, lang: "Algo", diff: "hard", title: "Interval Scheduling Maximization", concepts: "Greedy, Sorting, Intervals", problem: "Select maximum number of non-overlapping intervals. Prove why greedy (earliest end time) works.", why: "Resource allocation, scheduling, calendar apps. Greedy proof is what interviewers test.", examples: "Intervals [(1,4),(2,3),(3,5)] => select (2,3),(3,5) => 2 intervals", testInputs: "All overlapping => 1 interval selected", explanation: "Sort by end time. Greedily pick interval if start >= last selected end. Exchange argument proves optimality." },
  { id: 3124, lang: "Algo", diff: "hard", title: "Matrix Chain Multiplication", concepts: "Interval DP, Parenthesization", problem: "Find the minimum number of scalar multiplications to chain-multiply a sequence of matrices.", why: "Classic interval DP. Teaches optimal substructure for non-linear ordering problems.", examples: "Chains of dim [40x20, 20x30, 30x10, 10x30] => min ops", testInputs: "Single matrix => 0 ops", explanation: "dp[i][j] = min over k of dp[i][k] + dp[k+1][j] + cost(i,k,j). Build bottom-up from length 2." },
  { id: 3125, lang: "Algo", diff: "hard", title: "Longest Palindromic Subsequence", concepts: "2D DP, Strings", problem: "Find the length of the longest subsequence of a string that is a palindrome.", why: "Extension of LCS — relates to DNA sequence alignment and data compression.", examples: "s='bbbab' => 4 ('bbbb')", testInputs: "s='cbbd' => 2", explanation: "lps[i][j] = lps[i+1][j-1]+2 if s[i]==s[j], else max(lps[i+1][j], lps[i][j-1])." },
  { id: 3126, lang: "Algo", diff: "hard", title: "Minimum Cost to Connect All Points", concepts: "MST, Manhattan Distance", problem: "Given n points on a 2D plane, find minimum cost to connect all using Manhattan distance edges (MST).", why: "MST on implicit graphs — tests ability to construct graph from problem constraints.", examples: "Points: [[0,0],[2,2],[3,10],[5,2],[7,0]] => 20", testInputs: "Single point => 0", explanation: "Build virtual edges from all pairs using Manhattan distance. Apply Prim's or Kruskal's MST." },
  { id: 3127, lang: "Algo", diff: "hard", title: "Word Search II (Trie + DFS)", concepts: "Trie, DFS, Backtracking", problem: "Given a board and a list of words, find all words formed by adjacent cells. Use a Trie for pruning.", why: "Combines two data structures. Tests pruning ability — key for efficiency.", examples: "Board: [['o','a'],['e','t']], words=['eat','oat'] => ['eat','oat']", testInputs: "Empty word list => []", explanation: "Build Trie from words. DFS from each cell. Prune branch if no Trie path. Remove found words from Trie." },
  { id: 3128, lang: "Algo", diff: "hard", title: "Count of Smaller Numbers After Self", concepts: "Merge Sort, BIT, Divide & Conquer", problem: "Return an array where counts[i] is the number of elements to the right of nums[i] that are smaller.", why: "Classic hard problem. Tests divide & conquer or BIT variant for inversions counting.", examples: "Input: [5,2,6,1] => [2,1,1,0]", testInputs: "All same => [0,0,...,0]", explanation: "Merge sort: during merge, count how many from right half are placed before current left element." },
  { id: 3129, lang: "Algo", diff: "hard", title: "Shortest Path in Binary Matrix", concepts: "BFS, Matrix, 8-Directional", problem: "Find shortest path from top-left to bottom-right in a binary matrix (8 directions, 0=open).", why: "Multi-directional BFS on grids — common in game dev and robot path planning.", examples: "Matrix [[0,0,0],[1,1,0],[1,1,0]] => 4", testInputs: "Start or end is blocked => -1", explanation: "BFS with 8-directional neighbors. First time we reach end is shortest. O(n*m)." },
  { id: 3130, lang: "Algo", diff: "hard", title: "Reconstruct Itinerary (Euler Path)", concepts: "Graph, Hierholzer's Algorithm", problem: "Given airline tickets, reconstruct the itinerary in lexical order using Hierholzer's algorithm.", why: "Euler path in directed graph. Post-order DFS insight is non-obvious.", examples: "[['MUC','LHR'],['JFK','MUC'],['SFO','SJC'],['LHR','SFO']] => ['JFK','MUC','LHR','SFO','SJC']", testInputs: "Multiple valid paths => lexically smallest", explanation: "DFS with sorted adjacency lists. Post-order push to result. Reverse at end." },
  { id: 3131, lang: "Algo", diff: "hard", title: "Largest Rectangle in Histogram", concepts: "Stack, Monotonic Stack", problem: "Find the largest rectangle that can be formed in a histogram using a monotonic stack.", why: "Classic monotonic stack problem. Understanding the stack invariant is the key insight.", examples: "heights=[2,1,5,6,2,3] => 10", testInputs: "All equal heights => n * height", explanation: "Maintain increasing stack of indices. Pop when current < top. Area = top_height * (i - new_top - 1)." },
  { id: 3132, lang: "Algo", diff: "hard", title: "Minimum Number of Refueling Stops", concepts: "Greedy, Max-Heap", problem: "Find minimum stops to reach a target given stations with fuel. Greedily use the best fuel seen.", why: "Lazy greedy with max-heap. Tests deferred decision-making pattern.", examples: "target=100, startFuel=10, stations=[[10,60],[20,30],[30,30],[60,40]] => 2", testInputs: "Unreachable => -1", explanation: "Travel as far as possible. When stuck, fill up from the largest-fuel station seen so far (max-heap)." },
  { id: 3133, lang: "Algo", diff: "hard", title: "Find Median from Data Stream", concepts: "Two Heaps, Streaming", problem: "Design a data structure that supports addNum and findMedian efficiently using two heaps.", why: "Two-heap pattern is a classic streaming problem. Asked at Amazon, Google, Meta.", examples: "add(1), add(2), median()=1.5, add(3), median()=2", testInputs: "All same numbers => that number as median", explanation: "Max-heap for lower half, min-heap for upper half. Balance sizes to differ by at most 1." },
  { id: 3134, lang: "Algo", diff: "hard", title: "Smallest Range Covering K Lists", concepts: "Sliding Window, Min-Heap", problem: "Find the smallest range [a,b] such that at least one element from each of k sorted lists falls in [a,b].", why: "Complex multi-list sliding window using a heap. Amazon/Google hard interview problem.", examples: "lists=[[4,10,15,24,26],[0,9,12,20],[5,18,22,30]] => [20,24]", testInputs: "k=1 => [min,min] of that list", explanation: "Heap of (value, list_idx, element_idx). Expand range by tracking max. Advance min element." },
  { id: 3135, lang: "Algo", diff: "hard", title: "Median of Two Sorted Arrays", concepts: "Binary Search, Divide & Conquer", problem: "Find the median of two sorted arrays in O(log(m+n)). The most famous binary search problem.", why: "One of the hardest problems conceptually. Tests true binary search mastery.", examples: "nums1=[1,3], nums2=[2] => 2.0. nums1=[1,2], nums2=[3,4] => 2.5", testInputs: "One empty array => median of other", explanation: "Binary search on partition of smaller array. Ensure left half count = right half. Check boundary conditions." },
  { id: 3136, lang: "Algo", diff: "hard", title: "N-Queens Problem", concepts: "Backtracking, Bitmask", problem: "Place N queens on NxN board so none attack each other. Return all solutions.", why: "Classic backtracking. Bitmask variant is O(n!) with efficient constraint checking.", examples: "N=4 => 2 solutions", testInputs: "N=1 => 1 solution, N=2 => 0 solutions", explanation: "Track used columns, diagonals, anti-diagonals with sets or bitmask. Row by row placement." },
  { id: 3137, lang: "Algo", diff: "hard", title: "Sudoku Solver", concepts: "Backtracking, Constraint Propagation", problem: "Write a backtracking solver for 9x9 Sudoku. Use constraint propagation for pruning.", why: "Classic backtracking problem. Tests understanding of search space pruning.", examples: "Valid Sudoku board with some blanks => solved board", testInputs: "Empty board => solved with valid placement", explanation: "For each empty cell, try 1-9, check row/col/box constraints, recurse. Backtrack on failure." },
  { id: 3138, lang: "Algo", diff: "hard", title: "Expression Add Operators", concepts: "DFS, Backtracking, Operator Precedence", problem: "Add +, -, * between digits of a number string to reach a target value. Return all expressions.", why: "Complex backtracking with operator precedence handling. Tests careful state management.", examples: "num='123', target=6 => ['1+2+3','1*2*3']", testInputs: "num='000', target=0 => multiple solutions", explanation: "Track current value and last multiplied term (for undo on *). DFS through digit prefixes." },
  { id: 3139, lang: "Algo", diff: "hard", title: "Decode String with Nested Brackets", concepts: "Stack, Recursion", problem: "Decode encoded strings like 3[a2[c]] -> accaccacc. Handle arbitrarily nested encodings.", why: "Tests recursive stack-based string construction. Common in parsing and compiler design.", examples: "'3[a]2[bc]' => 'aaabcbc'. '3[a2[c]]' => 'accaccacc'", testInputs: "No brackets => return as-is", explanation: "Use a stack. Push (current_string, multiplier) on '['. On ']', pop and repeat current string." },
  { id: 3140, lang: "Algo", diff: "hard", title: "Swim in Rising Water", concepts: "Binary Search, Dijkstra, Min-Max Path", problem: "Find the minimum time T so you can swim from (0,0) to (n-1,n-1) in a grid where cells have elevation.", why: "Min-max path problem. Solvable by Dijkstra or binary search + BFS. Tests problem reformulation.", examples: "grid=[[0,2],[1,3]] => 3", testInputs: "Single cell => grid[0][0]", explanation: "Dijkstra: cost to reach cell = max(cost so far, grid[r][c]). Find minimum max-cost path." },
  { id: 3141, lang: "Algo", diff: "hard", title: "Cheapest Flights Within K Stops", concepts: "Graph, Bellman-Ford, BFS", problem: "Find cheapest flight from src to dst with at most k stops. Use Bellman-Ford limited to k+1 relaxations.", why: "Constrained shortest path. Bellman-Ford variation with iteration count as the constraint.", examples: "n=3, flights=[[0,1,100],[1,2,100],[0,2,500]], src=0, dst=2, k=1 => 200", testInputs: "k=0 and no direct flight => -1", explanation: "Run Bellman-Ford k+1 times on temporary copy of dist array to avoid using new edges in same iteration." },
  { id: 3142, lang: "Algo", diff: "hard", title: "Jump Game VI (Monotonic Deque DP)", concepts: "Monotonic Deque, DP", problem: "Maximize score jumping from index 0 to n-1, jumping at most k steps. Use monotonic deque.", why: "Sliding window max DP. Tests combining classic DP with efficient window queries.", examples: "nums=[1,-1,-2,4,-7,3], k=2 => 7", testInputs: "k >= n => single large jump", explanation: "dp[i] = nums[i] + max(dp[i-k..i-1]). Use deque to maintain max in O(1) per step." },
  { id: 3143, lang: "Algo", diff: "hard", title: "Count of Range Sum", concepts: "Merge Sort, Prefix Sum, Divide & Conquer", problem: "Count the number of range sums that lie in [lower, upper]. Use prefix sums + merge sort.", why: "Advanced merge sort application. Tests ability to extend classic algorithms.", examples: "nums=[-2,5,-1], lower=-2, upper=2 => 3", testInputs: "Empty array => 0", explanation: "Convert to prefix sums. During merge sort, count valid pairs [i,j] where prefix[j]-prefix[i] is in range." },
  { id: 3144, lang: "Algo", diff: "hard", title: "Maximum Gap (Bucket Sort)", concepts: "Bucket Sort, Pigeonhole Principle", problem: "Find maximum gap between successive elements in sorted form in O(n) time and space.", why: "Linear time sorting insight. Uses pigeonhole principle — tests mathematical reasoning.", examples: "Input: [3,6,9,1] => 3", testInputs: "n < 2 => 0", explanation: "Use n-1 buckets. Each bucket spans (max-min)/(n-1). Max gap must span bucket boundaries." },
  { id: 3145, lang: "Algo", diff: "hard", title: "Minimum Cost to Hire K Workers", concepts: "Sorting, Min-Heap, Ratio Optimization", problem: "Given workers with quality and wage, hire exactly k workers at minimum cost where ratios are respected.", why: "Sorting + heap with a sliding window of size k. Elegant greedy math.", examples: "quality=[10,20,5], wage=[70,50,30], k=2 => 105", testInputs: "k=1 => pick worker with minimum wage/quality ratio", explanation: "Sort by wage/quality ratio. For each captain ratio, take k lowest quality workers seen (min-heap by quality)." },
  { id: 3146, lang: "Algo", diff: "hard", title: "Minimum Number of Jumps II", concepts: "BFS, Greedy, Range Tracking", problem: "Reach last index in minimum jumps. Each element is max jump length from that position.", why: "Greedy BFS-like approach is O(n). Tests thinking in levels/ranges rather than individual cells.", examples: "nums=[2,3,1,1,4] => 2", testInputs: "nums=[1] => 0", explanation: "Track current reach and next reach. Increment jumps when you exhaust current reach. Update next reach per cell." },
  { id: 3147, lang: "Algo", diff: "hard", title: "Bitwise AND of Numbers Range", concepts: "Bit Manipulation, Shift", problem: "Find the bitwise AND of all numbers in range [left, right] in O(log n).", why: "Tests bit manipulation insight: bits that differ between left and right must be 0 in the result.", examples: "left=5, right=7 => 4 (0b101 & 0b110 & 0b111 = 0b100)", testInputs: "left=right => left", explanation: "Shift both right until equal. The common prefix is the answer. Shift left back by shift count." },
  { id: 3148, lang: "Algo", diff: "hard", title: "Gray Code Generation", concepts: "Bit Manipulation, Sequence", problem: "Generate an n-bit Gray code sequence (consecutive values differ by exactly 1 bit).", why: "Used in error correction, digital circuits, and rotary encoders. Tests bitwise XOR insight.", examples: "n=2 => [0,1,3,2] (00,01,11,10)", testInputs: "n=1 => [0,1]", explanation: "Gray(i) = i ^ (i >> 1). Generate 2^n values using this formula." },
  { id: 3149, lang: "Algo", diff: "hard", title: "Suffix Array with LCP", concepts: "String, Suffix Array, LCP Array", problem: "Build a suffix array for a string in O(n log^2 n). Build LCP array. Find longest repeated substring.", why: "Suffix arrays power text editors, genome sequencing, and full-text search.", examples: "s='banana' => sorted suffixes give array [5,3,1,0,4,2]", testInputs: "LCP array from suffix array => longest repeated substring", explanation: "Generate all suffixes with indices. Sort. Build LCP array using Kasai's algorithm to find longest repeated." },
  { id: 3150, lang: "Algo", diff: "hard", title: "Minimum Interval to Include Each Query", concepts: "Sorting, Min-Heap, Offline Processing", problem: "For each query point, find the size of the smallest interval that contains it.", why: "Offline query processing with sorted sweep. Tests ordering queries with events.", examples: "intervals=[[1,4],[2,4],[3,6],[4,4]], queries=[2,3,4,5] => [3,3,1,4]", testInputs: "No covering interval => -1", explanation: "Sort both. Min-heap of (size, end). For each query, add valid intervals and remove expired ones." },
  { id: 3151, lang: "Algo", diff: "hard", title: "Maximum Points on a Line", concepts: "Hash Map, Math, GCD", problem: "Given n points, find the maximum number of points that lie on the same line.", why: "Slope calculation with floating point pitfalls. GCD-based rational representation needed.", examples: "points=[[1,1],[2,2],[3,3]] => 3", testInputs: "Duplicate points => count all duplicates", explanation: "For each point, compute slope to every other as (dy/gcd, dx/gcd). Hash map most frequent slope." },
  { id: 3152, lang: "Algo", diff: "hard", title: "Stone Game Minimax", concepts: "Minimax, Game Theory, DP", problem: "Two players alternately remove stones from ends. Find if first player can guarantee a win. Prove mathematically.", why: "Minimax game theory. Also has a mathematical trick: even/odd indices. Tests both approaches.", examples: "piles=[5,3,4,5] => true", testInputs: "[3,7,2,3] => true", explanation: "Math: 1st player always wins (pick all even or all odd indexed). DP: dp[i][j] = max score difference player can achieve from subarray." },
  { id: 3153, lang: "Algo", diff: "hard", title: "Zuma Game (Interval DP)", concepts: "Interval DP, Memoization", problem: "Minimum moves to clear all balls in Zuma — group 3+ same-color adjacent balls to clear.", why: "Hard interval DP with state compression. Rare but tests deep memoization understanding.", examples: "board='RGBRGB' => 3 (each color pair split by shooting)", testInputs: "All same color => ceil(n/3) moves", explanation: "dp(l, r, k) = min moves to clear board[l..r] with k trailing balls same as board[r] attached." },
  { id: 3154, lang: "Algo", diff: "hard", title: "Longest Valid Parentheses", concepts: "Stack, DP, Two Passes", problem: "Find the length of the longest valid (well-formed) parentheses substring.", why: "3 different approaches: DP, stack, two-pass counter. All should be known.", examples: "s=')()())' => 4. s='(()' => 2", testInputs: "All open => 0. Alternating => n if even", explanation: "Stack approach: push index of '('. On ')', pop. Length = i - stack.top(). Handle empty stack edge case." },
  { id: 3155, lang: "Algo", diff: "hard", title: "Bus Routes (BFS on Sets)", concepts: "BFS, Graph, Layer Traversal", problem: "Find minimum number of bus routes to travel from source to target stop.", why: "BFS on bus routes (not stops). Treating routes as nodes prevents TLE.", examples: "routes=[[1,2,7],[3,6,7]], source=1, target=6 => 2", testInputs: "Source == target => 0", explanation: "Build stop-to-routes map. BFS over routes. Mark visited routes, not stops. Count bus changes." },
  { id: 3156, lang: "Algo", diff: "hard", title: "Jump Game VII (Prefix Sum BFS)", concepts: "BFS, Prefix Sum, Optimization", problem: "Can you jump from index 0 to last index given jump range [minJump, maxJump] and blocked cells?", why: "Prefix sum optimizes BFS to O(n) from O(n^2). Tests optimization of obvious solutions.", examples: "s='011010', minJump=2, maxJump=3 => true", testInputs: "All '1' except start => false", explanation: "Maintain reach pointer. For reachable cells, add [i+min, i+max] to reachable range using prefix sum." },
  { id: 3157, lang: "Algo", diff: "hard", title: "Count Vowel Substrings with At Most K Distinct", concepts: "Sliding Window, Hash Map", problem: "Count the number of substrings containing at most K distinct vowels. Use atMost(k) - atMost(k-1) trick.", why: "Advanced sliding window. 'Exactly K' via difference of 'at most K' is a reusable pattern.", examples: "s='cuaeio', k=2 => count substrings with exactly 2 distinct vowels", testInputs: "No vowels => depends on k definition", explanation: "atMost(k): expand right, shrink left when distinct > k. Track window sizes. Subtract atMost(k-1) for exact." }
];



export const codingChallenges = [
  { id: 1, lang: "Code", diff: "easy", title: "Two Sum", concepts: "Hash Map, Array", problem: "Given an array of integers and a target sum, return the indices of the two numbers that add up to the target. Each input has exactly one solution. You may not use the same element twice.", why: "Most common interview opener at every level. Tests hash map intuition and O(n) vs O(n²) tradeoff.", examples: "Input: nums=[2,7,11,15], target=9 => Output: [0,1]\nInput: nums=[3,2,4], target=6 => Output: [1,2]", testInputs: "nums=[3,3], target=6 => [0,1]\nnums=[-1,-2,-3,-4,-5], target=-8 => [2,4]", explanation: "Iterate once. For each num, check if (target - num) is already in your hash map. Store num -> index as you go. O(n) time, O(n) space." },
  { id: 2, lang: "Code", diff: "easy", title: "Valid Parentheses", concepts: "Stack", problem: "Given a string containing only '(', ')', '{', '}', '[', ']', determine if the input string is valid. A string is valid if every open bracket has a matching close bracket in the correct order.", why: "Classic stack problem. Appears in compiler design and code editor tools.", examples: "Input: '()[]{}' => true\nInput: '([)]' => false\nInput: '{[]}' => true", testInputs: "Input: '' => true (empty is valid)\nInput: '((' => false (unclosed)", explanation: "Push open brackets onto stack. For each close bracket, pop stack and verify it matches. At the end, stack must be empty." },
  { id: 3, lang: "Code", diff: "easy", title: "Best Time to Buy and Sell Stock", concepts: "Array, Single Pass, Min Tracking", problem: "Given an array of prices where prices[i] is the stock price on day i, find the maximum profit you can achieve from one buy and one sell. You must buy before you sell. If no profit is possible, return 0.", why: "Tests the pattern of tracking a running minimum while scanning forward.", examples: "Input: [7,1,5,3,6,4] => 5 (buy at 1, sell at 6)\nInput: [7,6,4,3,1] => 0 (prices always falling)", testInputs: "Input: [1] => 0\nInput: [2,4,1] => 2", explanation: "Track min_price seen so far. For each price, compute price - min_price. Track the max of those differences. O(n) time, O(1) space." },
  { id: 4, lang: "Code", diff: "easy", title: "Valid Anagram", concepts: "Hash Map, Sorting, Character Frequency", problem: "Given two strings s and t, return true if t is an anagram of s. An anagram uses the same characters with the same frequency.", why: "Tests character frequency counting — a foundational pattern reused in sliding window problems.", examples: "Input: s='anagram', t='nagaram' => true\nInput: s='rat', t='car' => false", testInputs: "s='', t='' => true\ns='a', t='ab' => false (different lengths)", explanation: "Sort both strings and compare, O(n log n). Or count character frequencies in a hash map, O(n). Compare frequency maps." },
  { id: 5, lang: "Code", diff: "easy", title: "Majority Element", concepts: "Boyer-Moore Voting, Hash Map", problem: "Given an array of size n, find the element that appears more than n/2 times. You may assume the majority element always exists.", why: "Two solutions: O(n) space with a map, and O(1) space with Boyer-Moore Voting — interviewers want both.", examples: "Input: [3,2,3] => 3\nInput: [2,2,1,1,1,2,2] => 2", testInputs: "Input: [1] => 1\nInput: [6,5,5] => 5", explanation: "Boyer-Moore: maintain candidate and count. If count=0, pick current as candidate. If current matches candidate, increment; else decrement. Final candidate is the majority." },
  { id: 6, lang: "Code", diff: "easy", title: "Linked List Cycle Detection", concepts: "Floyd's Algorithm, Two Pointers", problem: "Given the head of a linked list, determine if the list has a cycle. Follow-up: if there is a cycle, return the node where the cycle begins.", why: "Floyd's cycle detection is a classic algorithm. The follow-up (finding the cycle entry point) appears at higher levels.", examples: "List: 3->2->0->-4->back to 2 => true, cycle starts at node 2\nList: 1->2->null => false", testInputs: "Single node pointing to itself => true\nEmpty list => false", explanation: "Fast pointer moves 2 steps, slow pointer moves 1. If they meet, a cycle exists. To find the entry: reset one pointer to head, move both one step at a time — they meet at the cycle entry." },
  { id: 7, lang: "Code", diff: "easy", title: "Reverse Linked List", concepts: "Linked List, Iterative, Recursive", problem: "Given the head of a singly linked list, reverse the list and return the new head. Implement both iteratively and recursively.", why: "Pointer manipulation fundamentals. Interviewers want both solutions and clear explanation of the recursive call stack.", examples: "Input: 1->2->3->4->5 => 5->4->3->2->1\nInput: 1->2 => 2->1", testInputs: "Input: single node => same node\nInput: null => null", explanation: "Iterative: maintain prev=null, curr=head. At each step: save curr.next, point curr.next to prev, advance prev=curr, curr=saved. Recursive: reverse(head.next), then head.next.next = head, head.next = null." },
  { id: 8, lang: "Code", diff: "easy", title: "Climb Stairs", concepts: "DP, Fibonacci, Memoization", problem: "You can climb 1 or 2 steps at a time. How many distinct ways can you reach the top of n stairs?", why: "The entry-level DP problem. Recognizing the Fibonacci recurrence is the insight.", examples: "n=2 => 2 (1+1, 2)\nn=3 => 3 (1+1+1, 1+2, 2+1)\nn=4 => 5", testInputs: "n=1 => 1\nn=10 => 89", explanation: "dp[n] = dp[n-1] + dp[n-2]. You either arrived from n-1 (one step) or n-2 (two steps). Base cases: dp[1]=1, dp[2]=2. Can optimize to O(1) space by tracking only last two values." },
  { id: 9, lang: "Code", diff: "easy", title: "Binary Search", concepts: "Binary Search, Sorted Array, O(log n)", problem: "Given a sorted array of distinct integers, implement binary search. Return the index of the target, or -1 if not found. Follow-up: find the leftmost index of a target that appears multiple times.", why: "Binary search template (lo, hi, mid calculation) is reused in dozens of harder problems.", examples: "Input: [-1,0,3,5,9,12], target=9 => 4\nInput: [1,2,3], target=4 => -1", testInputs: "Single element equals target => 0\nTarget is first or last element", explanation: "lo=0, hi=len-1. mid = lo + (hi-lo)/2 (avoids overflow). If nums[mid]==target return mid. If target > nums[mid], lo=mid+1. Else hi=mid-1. Always check lo<=hi." },
  { id: 10, lang: "Code", diff: "easy", title: "Maximum Subarray (Kadane's)", concepts: "Kadane's Algorithm, DP", problem: "Given an integer array, find the contiguous subarray with the largest sum and return its sum.", why: "Kadane's algorithm is the canonical O(n) DP solution. Interviewers want the O(n) approach, not brute force.", examples: "Input: [-2,1,-3,4,-1,2,1,-5,4] => 6 (subarray [4,-1,2,1])\nInput: [1] => 1", testInputs: "All negative: [-3,-1,-2] => -1 (single element)\nAll positive: [1,2,3] => 6", explanation: "cur = max(nums[i], cur + nums[i]). If adding current element to running sum hurts, start fresh from current element. Track global max. O(n) time, O(1) space." },
  { id: 11, lang: "Code", diff: "easy", title: "Contains Duplicate", concepts: "Hash Set, Sorting", problem: "Given an integer array, return true if any value appears at least twice. Return false if every element is distinct.", why: "Simple but teaches set-based deduplication — a building block for harder problems.", examples: "Input: [1,2,3,1] => true\nInput: [1,2,3,4] => false", testInputs: "Input: [] => false\nInput: [1,1] => true", explanation: "Insert elements into a set one by one. If any element is already in the set, return true. O(n) time. Alternatively sort and check adjacent elements." },
  { id: 12, lang: "Code", diff: "easy", title: "Move Zeroes", concepts: "Two Pointers, In-Place", problem: "Given an integer array, move all zeroes to the end while maintaining the relative order of non-zero elements. Do it in-place without making a copy.", why: "Tests two-pointer in-place array manipulation — a pattern used in partition and Dutch National Flag problems.", examples: "Input: [0,1,0,3,12] => [1,3,12,0,0]\nInput: [0,0,1] => [1,0,0]", testInputs: "Input: [0] => [0]\nInput: [1,2,3] => [1,2,3] (no zeroes)", explanation: "Maintain a write pointer. Iterate: when non-zero, write to write pointer position and increment it. After pass, fill remaining positions with zeroes. O(n) time, O(1) space." },
  { id: 13, lang: "Code", diff: "easy", title: "Missing Number", concepts: "Math, XOR, Array", problem: "Given an array containing n distinct numbers in the range [0, n], find the one number that is missing.", why: "Two O(n) approaches: sum formula and XOR. Both show mathematical intuition that impresses interviewers.", examples: "Input: [3,0,1] => 2\nInput: [0,1] => 2\nInput: [9,6,4,2,3,5,7,0,1] => 8", testInputs: "Input: [0] => 1\nInput: [1] => 0", explanation: "Math: expected sum = n*(n+1)/2. Actual sum = sum of array. Difference is missing number. XOR: XOR all indices 0..n with all array values — every number except the missing one cancels out." },
  { id: 14, lang: "Code", diff: "easy", title: "Intersection of Two Arrays", concepts: "Hash Set, Two Pointers", problem: "Given two integer arrays, return an array of their intersection — elements that appear in both arrays. Each element in the result must be unique.", why: "Set intersection is a common data manipulation pattern.", examples: "Input: [1,2,2,1], [2,2] => [2]\nInput: [4,9,5], [9,4,9,8,4] => [9,4]", testInputs: "No common elements => []\nIdentical arrays => unique elements", explanation: "Add nums1 into a set. Iterate nums2, add to result set if it's in nums1 set. Convert result set to array. O(n+m) time." },
  { id: 15, lang: "Code", diff: "easy", title: "Palindrome Linked List", concepts: "Two Pointers, Reverse, Stack", problem: "Given the head of a singly linked list, return true if it is a palindrome. Can you do it in O(n) time and O(1) space?", why: "Combines multiple techniques: slow/fast pointer to find middle, reverse second half, compare.", examples: "Input: 1->2->2->1 => true\nInput: 1->2 => false", testInputs: "Single node => true\nTwo identical nodes => true", explanation: "Find mid with slow/fast pointers. Reverse second half in-place. Compare first half with reversed second half. Optionally restore the list. O(n) time, O(1) space." },
  { id: 16, lang: "Code", diff: "easy", title: "First Bad Version", concepts: "Binary Search, API calls, Minimize calls", problem: "You have n versions [1..n]. Some version first became bad, and all subsequent versions are also bad. The API bool isBadVersion(n) is expensive. Find the first bad version minimizing API calls.", why: "Tests applying binary search to a non-obvious domain. The insight of searching for a boundary is key.", examples: "n=5, first bad=4 => check 3(false), 4(true), 3.5->check 4 => ans=4", testInputs: "n=1, bad=1 => 1\nAll bad => 1", explanation: "Binary search. If isBadVersion(mid) is true, the first bad could be mid or earlier — hi=mid. If false, first bad is later — lo=mid+1. Return lo." },
  { id: 17, lang: "Code", diff: "easy", title: "Merge Two Sorted Lists", concepts: "Linked List, Merge, Recursion", problem: "Given the heads of two sorted linked lists, merge them into one sorted linked list and return its head.", why: "Foundational merge operation used in merge sort. Tests clean pointer manipulation.", examples: "Input: 1->2->4, 1->3->4 => 1->1->2->3->4->4\nInput: [], [] => []", testInputs: "One list empty => return other list unchanged", explanation: "Use a dummy head node to simplify edge cases. Compare heads, attach smaller node, advance that pointer. After one list exhausts, attach the other's remaining nodes directly." },
  { id: 18, lang: "Code", diff: "easy", title: "Single Number", concepts: "XOR, Bit Manipulation", problem: "Given an array where every element appears twice except one, find the single element. Solve in O(n) time and O(1) space without extra data structures.", why: "XOR trick (a^a=0, a^0=a) is a key bit manipulation insight asked frequently.", examples: "Input: [2,2,1] => 1\nInput: [4,1,2,1,2] => 4", testInputs: "Input: [1] => 1\nInput: [0,0,5] => 5", explanation: "XOR all elements. Duplicate elements cancel (a^a=0). The single element remains (0^a=a). O(n) time, O(1) space." },
  { id: 19, lang: "Code", diff: "easy", title: "Merge Sorted Array", concepts: "Two Pointers, In-Place Merge", problem: "Merge nums2 into nums1 in-place. nums1 has extra zeros at the end to accommodate nums2. Start filling from the back to avoid overwriting.", why: "In-place merge by filling from the back is a clever technique that avoids a temporary array.", examples: "nums1=[1,2,3,0,0,0], m=3, nums2=[2,5,6], n=3 => [1,2,2,3,5,6]", testInputs: "nums2 is empty => nums1 unchanged\nnums1 has only zeros (m=0) => copy nums2", explanation: "Three pointers: i=m-1, j=n-1, k=m+n-1. Compare nums1[i] and nums2[j], place larger at nums1[k]. If nums2 has remaining elements after nums1 exhausts, copy them." },
  { id: 20, lang: "Code", diff: "easy", title: "Roman to Integer", concepts: "Hash Map, String Parsing", problem: "Convert a Roman numeral string to an integer. Values: I=1, V=5, X=10, L=50, C=100, D=500, M=1000. Subtraction rule: IV=4, IX=9, XL=40, XC=90, CD=400, CM=900.", why: "Tests parsing rules with a simple but complete spec. Appears in interviews as a warm-up problem.", examples: "Input: 'III' => 3\nInput: 'MCMXCIV' => 1994\nInput: 'IX' => 9", testInputs: "Input: 'LVIII' => 58\nInput: 'III' => 3", explanation: "Scan right to left. If current value is less than the value after it (already processed), subtract current. Otherwise add it. No need for special-case subtraction pairs." },

  { id: 21, lang: "Code", diff: "medium", title: "LRU Cache", concepts: "Doubly Linked List, Hash Map, O(1)", problem: "Design and implement a Least Recently Used cache with O(1) get and put operations. The cache has a fixed capacity. When it's full, evict the least recently used entry.", why: "LRU cache is one of the most common system design coding problems. It tests data structure composition.", examples: "LRUCache(2)\nput(1,1), put(2,2), get(1)=>1, put(3,3)(evicts 2), get(2)=>-1", testInputs: "Accessing existing key makes it most recent.\nUpdating existing key with put() also refreshes recency.", explanation: "Combine a hash map (key -> node) for O(1) lookup with a doubly linked list for O(1) move-to-front and O(1) eviction from tail. Dummy head and tail simplify edge cases." },
  { id: 22, lang: "Code", diff: "medium", title: "Number of Islands", concepts: "BFS/DFS, Grid, Connected Components", problem: "Given a 2D grid of '1's (land) and '0's (water), count the number of islands. An island is surrounded by water and formed by connecting adjacent lands horizontally or vertically.", why: "Grid BFS/DFS is one of the most common interview problem types. Number of Islands is the canonical example.", examples: "Input: [['1','1','0'],['0','1','0'],['0','0','1']] => 2", testInputs: "All water => 0\nAll land => 1\nSingle cell of land => 1", explanation: "For each unvisited '1', launch BFS/DFS marking all connected cells as visited. Increment island count. O(n*m) time. Modify grid in-place or use a visited set." },
  { id: 23, lang: "Code", diff: "medium", title: "Merge Intervals", concepts: "Sorting, Interval Merging", problem: "Given an array of intervals [start, end], merge all overlapping intervals and return a list of non-overlapping intervals.", why: "Interval problems appear constantly in scheduling, calendar, and range query questions.", examples: "Input: [[1,3],[2,6],[8,10],[15,18]] => [[1,6],[8,10],[15,18]]\nInput: [[1,4],[4,5]] => [[1,5]]", testInputs: "Non-overlapping intervals => unchanged\nAll overlapping => single interval", explanation: "Sort by start time. Iterate: if current interval overlaps the last merged interval (current.start <= last.end), merge by updating last.end = max(last.end, current.end). Otherwise append." },
  { id: 24, lang: "Code", diff: "medium", title: "3Sum", concepts: "Two Pointers, Sorting, Deduplication", problem: "Given an integer array, return all unique triplets [a,b,c] such that a+b+c=0. The solution set must not contain duplicate triplets.", why: "3Sum tests sorting + two pointers and the crucial deduplication step that many candidates miss.", examples: "Input: [-1,0,1,2,-1,-4] => [[-1,-1,2],[-1,0,1]]\nInput: [0,0,0] => [[0,0,0]]", testInputs: "Input: [0,0,0,0] => [[0,0,0]] (no duplicates)\nInput: [1,2,-2,-1] => [] (no zero triplets)", explanation: "Sort. For each i, use two pointers lo=i+1, hi=end. Skip duplicate values of nums[i]. After finding a triplet, skip duplicate lo and hi values too." },
  { id: 25, lang: "Code", diff: "medium", title: "Group Anagrams", concepts: "Hash Map, Sorting, String Hashing", problem: "Given an array of strings, group anagrams together. Return a list of groups, each containing words that are anagrams of each other.", why: "Tests canonical form selection as a hash map key — a reusable pattern.", examples: "Input: ['eat','tea','tan','ate','nat','bat'] => [['eat','tea','ate'],['tan','nat'],['bat']]", testInputs: "Input: [''] => [['']]\nInput: ['a'] => [['a']]", explanation: "Key insight: anagrams have the same sorted string. Use sorted(word) as the hash map key. Group words by key. Alternative: use character frequency tuple as key (faster for long strings)." },
  { id: 26, lang: "Code", diff: "medium", title: "Top K Frequent Elements", concepts: "Heap, Bucket Sort, Hash Map", problem: "Given an integer array and integer k, return the k most frequent elements. Your algorithm must be better than O(n log n).", why: "The O(n) bucket sort solution is the insight interviewers look for. O(n log k) with heap is also acceptable.", examples: "Input: [1,1,1,2,2,3], k=2 => [1,2]\nInput: [1], k=1 => [1]", testInputs: "All same frequency: pick any k elements.", explanation: "Count frequencies. Bucket sort: create n+1 buckets where bucket[i] holds elements with frequency i. Scan from highest bucket down, collect k elements. O(n) time." },
  { id: 27, lang: "Code", diff: "medium", title: "Subarray Sum Equals K", concepts: "Prefix Sum, Hash Map", problem: "Given an integer array and integer k, return the total number of continuous subarrays whose sum equals k.", why: "The prefix sum + hash map pattern solves this in O(n). Brute force is O(n²) — interviewers want the optimal solution.", examples: "Input: [1,1,1], k=2 => 2\nInput: [1,2,3], k=3 => 2 ([1,2] and [3])", testInputs: "Negative numbers: [-1,-1,1], k=-1 => 3\nk=0: count subarrays that sum to 0", explanation: "prefixSum[j] - prefixSum[i] = k means subarray [i+1..j] sums to k. For each prefix sum, check if (prefixSum - k) exists in a frequency map. Seed map with {0:1} for subarrays starting at index 0." },
  { id: 28, lang: "Code", diff: "medium", title: "Coin Change", concepts: "Dynamic Programming, Bottom-Up, Unbounded Knapsack", problem: "Given coin denominations and an amount, find the minimum number of coins needed to make that amount. You can use each coin unlimited times. Return -1 if it's not possible.", why: "Canonical bottom-up DP problem. Tests building a DP table and understanding state transitions.", examples: "Input: coins=[1,2,5], amount=11 => 3 (5+5+1)\nInput: coins=[2], amount=3 => -1", testInputs: "amount=0 => 0\ncoins=[1], large amount => amount", explanation: "dp[i] = minimum coins for amount i. Initialize dp[0]=0, rest to infinity. For each amount i and each coin: dp[i] = min(dp[i], dp[i-coin]+1) if i>=coin." },
  { id: 29, lang: "Code", diff: "medium", title: "Word Break", concepts: "DP, Trie, BFS, Memoization", problem: "Given a string s and a dictionary of words, determine if s can be segmented into a space-separated sequence of dictionary words.", why: "String DP with substring matching. Multiple valid approaches show problem-solving flexibility.", examples: "Input: s='leetcode', wordDict=['leet','code'] => true\nInput: s='applepenapple', wordDict=['apple','pen'] => true\nInput: s='catsandog', wordDict=['cats','dog','sand','and','cat'] => false", testInputs: "Same word used multiple times: 'appleapple', ['apple'] => true", explanation: "dp[i] = can we segment s[0..i]. dp[0]=true. For each i, check all j<i: if dp[j] and s[j..i] in dict, dp[i]=true. O(n²) time or O(n*L) with Trie." },
  { id: 30, lang: "Code", diff: "medium", title: "Search in Rotated Sorted Array", concepts: "Binary Search, Rotation Detection", problem: "A sorted array was rotated at some pivot. Given the rotated array and a target, find the target's index in O(log n). Array has no duplicate values.", why: "Modified binary search is a very common interview pattern. The key insight is determining which half is sorted.", examples: "Input: [4,5,6,7,0,1,2], target=0 => 4\nInput: [4,5,6,7,0,1,2], target=3 => -1", testInputs: "Not rotated: [1,2,3], target=2 => 1\nSingle element equals target => 0", explanation: "At each step, one half is guaranteed sorted. Check which half: if nums[lo]<=nums[mid], left is sorted. Check if target falls in the sorted half. If yes, narrow to that half; otherwise search the other." },
  { id: 31, lang: "Code", diff: "medium", title: "Course Schedule (Cycle Detection)", concepts: "Topological Sort, DFS, BFS, Kahn's Algorithm", problem: "There are n courses. Some courses have prerequisites [a,b] meaning you must take b before a. Determine if it's possible to finish all courses. Return true if there's no cycle in the prerequisite graph.", why: "Cycle detection in a directed graph. Can be solved with DFS (coloring) or BFS (Kahn's). Both approaches should be known.", examples: "Input: n=2, prerequisites=[[1,0]] => true\nInput: n=2, prerequisites=[[1,0],[0,1]] => false (cycle)", testInputs: "n=1, no prerequisites => true\nn=3, chain 0->1->2->0 => false", explanation: "Build adjacency list. DFS: use 3 states (unvisited, visiting, visited). If you visit a 'visiting' node, cycle found. BFS: start from 0-in-degree nodes, process neighbors, count finished nodes — if count != n, cycle exists." },
  { id: 32, lang: "Code", diff: "medium", title: "Jump Game", concepts: "Greedy, DP", problem: "Given an array where nums[i] is the max jump length from index i, determine if you can reach the last index from index 0.", why: "Greedy O(n) solution is cleaner than DP. Knowing when greedy works vs DP is a key skill.", examples: "Input: [2,3,1,1,4] => true\nInput: [3,2,1,0,4] => false (stuck at index 3)", testInputs: "Input: [0] => true (already at last index)\nInput: [1,0,0] => false", explanation: "Track max_reach = 0. Iterate: if i > max_reach, you can't get here — return false. Otherwise max_reach = max(max_reach, i + nums[i]). If you finish the loop, return true." },
  { id: 33, lang: "Code", diff: "medium", title: "Longest Substring Without Repeating Characters", concepts: "Sliding Window, Hash Map", problem: "Given a string, find the length of the longest substring without repeating characters.", why: "The sliding window pattern is used in dozens of problems. This is the entry-level sliding window example.", examples: "Input: 'abcabcbb' => 3 ('abc')\nInput: 'bbbbb' => 1 ('b')\nInput: 'pwwkew' => 3 ('wke')", testInputs: "Input: '' => 0\nInput: 'au' => 2 (all unique)", explanation: "Sliding window with a hash map tracking character -> latest index. When duplicate found, move left pointer to max(left, last_seen[char]+1). Track max window size." },
  { id: 34, lang: "Code", diff: "medium", title: "Unique Paths", concepts: "2D DP, Math (Combinatorics)", problem: "A robot starts at the top-left of an m x n grid. It can only move right or down. How many unique paths are there to reach the bottom-right corner?", why: "Classic 2D DP. Also solvable with combinatorics (C(m+n-2, m-1)). Interviewers value knowing both approaches.", examples: "Input: m=3, n=7 => 28\nInput: m=3, n=2 => 3", testInputs: "m=1 or n=1 => 1 (only one path along the edge)\nm=2, n=2 => 2", explanation: "dp[i][j] = dp[i-1][j] + dp[i][j-1]. Top row and left column all = 1. Math: choose m-1 down moves from m+n-2 total moves = C(m+n-2, m-1)." },
  { id: 35, lang: "Code", diff: "medium", title: "Decode Ways", concepts: "DP, String Parsing, Edge Cases", problem: "A message encoded with A=1, B=2, ..., Z=26 can be decoded in multiple ways. Given a string of digits, count the number of ways to decode it.", why: "Requires careful handling of '0' and two-digit numbers — a DP problem with many edge cases.", examples: "Input: '12' => 2 ('AB' or 'L')\nInput: '226' => 3 ('BZ','VF','BBF')\nInput: '06' => 0 (invalid, leading zero)", testInputs: "Input: '10' => 1 (only 'J')\nInput: '110' => 1\nInput: '100' => 0", explanation: "dp[i] = ways to decode first i characters. One-char decode: dp[i] += dp[i-1] if s[i-1] != '0'. Two-char decode: dp[i] += dp[i-2] if '10' <= s[i-2..i-1] <= '26'." },

  { id: 51, lang: "Code", diff: "hard", title: "Trapping Rain Water", concepts: "Two Pointers, Stack, Prefix Max", problem: "Given n non-negative integers representing an elevation map, compute how much water it can trap after raining.", why: "Classic hard array problem. The two-pointer O(1) space solution is what separates strong candidates.", examples: "Input: [0,1,0,2,1,0,1,3,2,1,2,1] => 6\nInput: [4,2,0,3,2,5] => 9", testInputs: "All same height => 0\nMonotonically increasing => 0", explanation: "Two pointers from both ends. Track left_max and right_max. Water at position = min(left_max, right_max) - height[i]. Move pointer from the side with lower max height." },
  { id: 52, lang: "Code", diff: "hard", title: "Minimum Window Substring", concepts: "Sliding Window, Hash Map, Two Pointers", problem: "Given strings s and t, return the minimum window in s that contains all characters of t. If no such window exists, return empty string.", why: "Advanced sliding window requiring two frequency maps and a count of satisfied characters.", examples: "Input: s='ADOBECODEBANC', t='ABC' => 'BANC'\nInput: s='a', t='a' => 'a'\nInput: s='a', t='aa' => ''", testInputs: "t has duplicate chars: account for required frequency.\nt longer than s => ''", explanation: "Expand right pointer building window. When all chars satisfied, contract left pointer. Track: need (required counts), have (current counts), formed (how many chars meet required count). Update min window when formed == need size." },
  { id: 53, lang: "Code", diff: "hard", title: "Merge K Sorted Lists", concepts: "Min Heap, Divide & Conquer, Merge", problem: "Given an array of k sorted linked lists, merge them into one sorted linked list.", why: "Classic heap application. Divide and conquer is an alternative. Both are expected at senior level.", examples: "Input: [[1,4,5],[1,3,4],[2,6]] => 1->1->2->3->4->4->5->6", testInputs: "k=0, no lists => null\nSome empty lists => merge non-empty", explanation: "Min heap of (value, index, node). Pop minimum, append to result, push that node's next if exists. O(N log k) time where N is total nodes." },
  { id: 54, lang: "Code", diff: "hard", title: "Word Ladder (BFS Shortest Path)", concepts: "BFS, Graph, Word Transformation", problem: "Given beginWord, endWord, and a wordList, find the length of the shortest transformation sequence from beginWord to endWord where each step changes exactly one letter and each intermediate word must be in the wordList.", why: "Implicit graph construction + BFS for shortest path. Building the graph is the key challenge.", examples: "Input: begin='hit', end='cog', list=['hot','dot','dog','lot','log','cog'] => 5\n(hit->hot->dot->dog->cog)", testInputs: "endWord not in list => 0\nbeginWord == endWord => 1", explanation: "BFS from beginWord. For each word, try replacing each character with a-z. If the new word is in the wordSet and unvisited, add to queue. Return level when endWord found." },
  { id: 55, lang: "Code", diff: "hard", title: "Longest Valid Parentheses", concepts: "Stack, DP, Two Pass", problem: "Given a string of '(' and ')', find the length of the longest valid (well-formed) parentheses substring.", why: "Three distinct O(n) approaches exist: DP, stack, and two-pass counter. Knowing all three shows breadth.", examples: "Input: '(()' => 2\nInput: ')()())' => 4\nInput: '' => 0", testInputs: "All open '(((' => 0\nAll closed ')))' => 0\nPerfect '()()()' => 6", explanation: "Stack approach: push -1 as base. Push '(' indices. On ')', pop top — if stack empty push current index as new base; else length = i - stack.top(). Track max length." },
  { id: 56, lang: "Code", diff: "hard", title: "N-Queens", concepts: "Backtracking, Constraint Propagation", problem: "Place n queens on an n×n chessboard so no two queens attack each other. Return all distinct solutions. Each solution is a board configuration as a list of strings.", why: "N-Queens is the canonical backtracking problem. Efficient constraint checking with sets for columns/diagonals is key.", examples: "n=4 => [['.Q..','...Q','Q...','..Q.'],['..Q.','Q...','...Q','.Q..']]", testInputs: "n=1 => [['Q']]\nn=2 => [] (no solution)", explanation: "Row by row placement. For each row, try each column. Use sets for occupied columns, diagonals (r-c), anti-diagonals (r+c). O(n!) time. Backtrack by removing from sets." },
  { id: 57, lang: "Code", diff: "hard", title: "Serialize/Deserialize Binary Tree", concepts: "BFS, DFS, String Encoding", problem: "Design an algorithm to serialize a binary tree to a string and deserialize the string back. There is no restriction on your format — define your own.", why: "Tests ability to encode a recursive structure into a linear format. Format choice and null handling are key.", examples: "root=[1,2,3,null,null,4,5]\nserialize => '1,2,3,null,null,4,5'\ndeserialize => reconstructs original tree", testInputs: "Empty tree => 'null'\nSingle node => '1,null,null'", explanation: "BFS (level-order): use queue, encode 'null' for missing children. Deserialize: queue-based reconstruction. DFS (preorder): encode left then right. Deserialize with an index pointer." },
  { id: 58, lang: "Code", diff: "hard", title: "Find Median from Data Stream", concepts: "Two Heaps, Streaming, Balance Invariant", problem: "Design a data structure that supports adding numbers from a data stream and finding the median at any time. addNum(int num) and findMedian() must work efficiently.", why: "The two-heap solution is O(log n) per insertion, O(1) for median. A classic design problem.", examples: "add(1), add(2), median=1.5, add(3), median=2.0", testInputs: "All same numbers => that number as median.\nEven count => average of two middle values.", explanation: "Max-heap for lower half, min-heap for upper half. Invariant: sizes differ by at most 1. On add: push to max-heap, then push max-heap.top to min-heap. If min-heap larger, rebalance. Median: top of larger heap or average of both tops." },
  { id: 59, lang: "Code", diff: "hard", title: "Sliding Window Maximum", concepts: "Monotonic Deque, Sliding Window", problem: "Given an array and a window size k, return the maximum of each window as it slides through the array. Achieve O(n) time.", why: "The monotonic deque is non-obvious. O(n) vs O(nk) brute force is a common differentiator.", examples: "Input: [1,3,-1,-3,5,3,6,7], k=3 => [3,3,5,5,6,7]", testInputs: "k=1 => original array\nAll decreasing => first element of each window", explanation: "Deque stores indices in decreasing order of their values. For each new element: remove from back while nums[back] < current. Remove from front if out of window. Front is always current window's max." },
  { id: 60, lang: "Code", diff: "hard", title: "Edit Distance", concepts: "2D DP, String Transformation", problem: "Given two words word1 and word2, return the minimum number of operations (insert, delete, replace) to convert word1 to word2.", why: "Edit distance (Levenshtein) is used in spell checkers, diff tools, and DNA sequence alignment.", examples: "Input: 'horse', 'ros' => 3\nInput: 'intention', 'execution' => 5", testInputs: "Either string empty => length of the other\nIdentical strings => 0", explanation: "dp[i][j] = min ops to convert word1[0..i] to word2[0..j]. If chars match: dp[i][j] = dp[i-1][j-1]. Else: min(dp[i-1][j]+1(delete), dp[i][j-1]+1(insert), dp[i-1][j-1]+1(replace))." }
];

