export const dbAdvancedChallenges = [
  { id: 5001, lang: "MongoDB", diff: "medium", title: "Aggregation Pipeline Deep Dive", concepts: "Aggregation, $group, $lookup, $unwind, $facet", problem: "Design an aggregation pipeline that: (1) joins orders with customers via $lookup, (2) groups by customer region, (3) computes revenue percentile using $bucketAuto, (4) uses $facet for multi-dimensional analytics in a single pass.", why: "Aggregation is MongoDB's core analytics engine. Multi-stage pipelines are the #1 interview topic for MongoDB roles.", examples: "db.orders.aggregate([$lookup, $unwind, $group, $facet]) => stats per region with revenue buckets", testInputs: "10M order documents, low-latency requirement => must use indexes", explanation: "$lookup performs a join. $unwind deconstructs arrays. $group accumulates. $facet runs multiple sub-pipelines in one pass. Always place $match early to leverage indexes." },
  { id: 5002, lang: "MongoDB", diff: "medium", title: "Indexing Strategies and ESR Rule", concepts: "Compound Index, Covered Query, ESR Rule, explain()", problem: "Given: db.users.find({country:'US', age:{$gt:25}}).sort({createdAt:-1}), design the optimal compound index. Explain the ESR rule (Equality, Sort, Range). Verify with explain('executionStats').", why: "Poor indexing is the #1 cause of MongoDB performance issues. ESR rule is a must-know for any backend interview.", examples: "Index {country:1, createdAt:-1, age:1} vs {country:1, age:1, createdAt:-1} — which wins and why?", testInputs: "explain shows IXSCAN vs COLLSCAN. TotalDocsExamined should equal nReturned for a covered query.", explanation: "ESR Rule: Equality fields first, then Sort fields, then Range fields. A covered query returns results from the index alone (no document fetch). Index intersection is less efficient than compound indexes." },
  { id: 5003, lang: "MongoDB", diff: "medium", title: "Schema Design: Embedding vs Referencing", concepts: "Data Modeling, 1-N, N-N, Denormalization, Extended Reference Pattern", problem: "Design a schema for a blog platform with users, posts, and comments. When do you embed comments vs reference them? Explain the 16MB document limit impact, and how the Extended Reference Pattern and Subset Pattern solve it.", why: "MongoDB schema design is fundamentally different from SQL. This is the most common MongoDB senior interview topic.", examples: "Small # comments => embed. Thousands of comments => reference. Frequently-read fields => denormalize into parent.", testInputs: "Model a social feed where each post has likes, comments, media. Optimize for feed read latency.", explanation: "Embed for: data read together, small bounded size, one-to-few. Reference for: large arrays, many-to-many, data accessed independently. Extended Reference: embed only frequently-used fields of referenced doc." },
  { id: 5004, lang: "MongoDB", diff: "medium", title: "Multi-Document Transactions and ACID", concepts: "Multi-Document Transactions, ACID, WiredTiger, Session", problem: "Implement a bank transfer between two accounts using a multi-document transaction. Explain when MongoDB guarantees ACID, the performance cost, and alternatives like the Two-Phase Commit pattern for pre-v4.0.", why: "MongoDB added multi-document ACID transactions in v4.0. Understanding when to use them (and when not to) is critical.", examples: "session.startTransaction(); debit(fromAcc); credit(toAcc); session.commitTransaction();", testInputs: "Simulate failure mid-transaction => both operations rolled back", explanation: "WiredTiger provides document-level locking. Multi-doc transactions add cross-document atomicity at the cost of latency and lock contention. Prefer single-document atomic operations where possible." },
  { id: 5005, lang: "MongoDB", diff: "medium", title: "Change Streams and CDC Pipelines", concepts: "Change Streams, Oplog, Event-Driven, CDC, resumeToken", problem: "Build a change stream listener that watches an orders collection and triggers downstream events for status updates. Explain how change streams work under the hood using the oplog. Handle resumeToken for fault tolerance.", why: "Change streams are MongoDB's CDC mechanism. Used in event-driven microservices and real-time data pipelines.", examples: "collection.watch([{$match:{operationType:'update'}}]).on('change', handler)", testInputs: "App restart mid-stream => resume from resumeToken. Node failure => oplog window matters.", explanation: "Change streams are built on the oplog (capped collection). resumeToken lets you resume after failure. $match filters only relevant operations. Oplog retention window limits how far back you can resume." },
  { id: 5006, lang: "MongoDB", diff: "hard", title: "Sharding Architecture and Shard Key Design", concepts: "Horizontal Scaling, Shard Key, Chunk Migration, Hotspot, Hashed vs Ranged", problem: "Design a sharding strategy for a time-series IoT platform with 1B documents. Explain: (1) ranged vs hashed sharding, (2) why a monotonically increasing shard key (like timestamp) creates hotspots, (3) how compound shard keys balance write distribution.", why: "Sharding is MongoDB's primary horizontal scaling mechanism. Bad shard key design is a common production disaster.", examples: "Bad: {timestamp:1} => all writes to one shard. Good: {deviceId:1, timestamp:1} => distribute by device.", testInputs: "Write throughput test with ranged vs hashed shard key. Measure chunk distribution imbalance.", explanation: "Ranged sharding: good for range queries but prone to hotspots. Hashed sharding: even distribution but no range query efficiency. Compound key (category + time) balances both. Avoid low-cardinality shard keys." },
  { id: 5007, lang: "MongoDB", diff: "hard", title: "WiredTiger Storage Engine Internals", concepts: "B-Tree, Journal, Checkpoint, Compression, MVCC, Cache Eviction", problem: "Explain how WiredTiger manages: (1) concurrent reads via MVCC snapshots, (2) durability via journaling and checkpoints, (3) document compression (snappy/zlib/zstd), (4) cache eviction under memory pressure.", why: "Deep storage engine knowledge differentiates senior engineers. Helps debug performance issues and tune deployments.", examples: "readConcern:'snapshot' => consistent view via MVCC. checkpoint every 60s or 2GB journal.", testInputs: "High write workload => journal flush frequency impact. Memory pressure => cache eviction and read performance.", explanation: "WiredTiger uses B-trees for data and indexes. MVCC provides snapshot isolation without read-write locking. Journal provides crash recovery between checkpoints. Default cache is 50% of RAM minus 1GB." },
  { id: 5008, lang: "MongoDB", diff: "hard", title: "Atlas Search: Lucene Integration", concepts: "Lucene, Inverted Index, Search Pipeline, Autocomplete, Edge N-Gram", problem: "Design a product search feature using Atlas Search (Lucene-based). Implement: (1) full-text search with relevance scoring, (2) faceted search for filters, (3) autocomplete using edge n-grams, (4) explain how Atlas Search syncs with MongoDB data via oplog tailing.", why: "Atlas Search integrates Lucene directly with MongoDB. Understanding the sync mechanism and index types separates architects from developers.", examples: "$search: {index:'products', text:{query:'laptop', path:'name'}, compound:{filter:[{term:{field:'inStock',query:true}}]}}", testInputs: "Data written to MongoDB => indexed by Atlas Search within seconds via oplog tailing", explanation: "Atlas Search runs a Lucene index alongside MongoDB. Syncs via oplog tailing. Edge n-gram analyzer creates tokens for prefix matching (autocomplete). $search stage must be first in aggregation pipeline." },
  { id: 5009, lang: "MongoDB", diff: "hard", title: "Time Series Collections and Bucketing", concepts: "Time Series, Columnar Storage, Bucketing Pattern, TTL, Granularity", problem: "Design a time-series collection for IoT sensor data (1M readings/sec). Explain how MongoDB's native timeseries collections use columnar storage internally, how bucketing reduces document count, and how to configure TTL for data retention.", why: "MongoDB 5.0 native time series is a major feature. IoT and monitoring use cases are extremely common at scale.", examples: "db.createCollection('sensor_data', {timeseries:{timeField:'ts',metaField:'sensorId',granularity:'seconds'}})", testInputs: "Compare query performance: regular collection vs timeseries collection for range queries on time.", explanation: "MongoDB buckets time series data internally (multiple readings per document). Columnar compression optimizes range reads. Bucket boundaries align with granularity setting. TTL on timeField automatically expires old data." },
  { id: 5010, lang: "MongoDB", diff: "hard", title: "Replica Set Internals and Failover Behavior", concepts: "Replica Set, Oplog, Election, Write Concern, Read Preference, Rollback", problem: "Explain: (1) how replica set elections work (Raft-based voting), (2) what happens to in-flight writes during failover, (3) how writeConcern:majority ensures durability, (4) when to use readPreference:secondaryPreferred and its consistency tradeoffs.", why: "High availability design requires deep understanding of replica set behavior. These are common staff/principal engineer questions.", examples: "writeConcern:{w:'majority',j:true} => wait for majority of nodes + journal flush before ack", testInputs: "Kill primary => measure election time (~10-30s). Writes during election => check rollback behavior.", explanation: "Elections require majority vote. Candidate with highest optime wins. Writes acknowledged before majority replication may be rolled back on failover. readPreference:secondary gives stale reads but reduces primary load." },

  { id: 5051, lang: "SQL", diff: "medium", title: "Query Execution Plan Deep Dive", concepts: "EXPLAIN ANALYZE, Index Scan, Hash Join, Nested Loop, Cost Estimation", problem: "Run EXPLAIN ANALYZE on: SELECT * FROM orders o JOIN customers c ON o.customer_id=c.id WHERE c.country='US' AND o.amount > 100 ORDER BY o.created_at DESC. Identify nested loop vs hash join vs merge join, when each is chosen, and how to force an index hint.", why: "Reading execution plans is the most critical skill for SQL performance optimization. Asked in every senior backend interview.", examples: "EXPLAIN ANALYZE shows: Seq Scan on orders (cost=0.00..45231.00), Hash Join (cost=12.50..67890.00)", testInputs: "No index => Seq Scan. Add index on (customer_id, amount) => Index Scan. Measure actual rows vs estimated.", explanation: "Planner chooses join method based on table statistics. Nested loop: good for small tables. Hash join: good for large unindexed joins. Merge join: good for pre-sorted data. ANALYZE updates statistics for better estimates." },
  { id: 5052, lang: "SQL", diff: "medium", title: "Advanced Window Functions Patterns", concepts: "PARTITION BY, ROWS vs RANGE, Running Totals, Gap-and-Island, Sessionization", problem: "Solve: (1) running total that resets per partition, (2) find gaps in a sequential ID series (gaps and islands), (3) sessionization: group events into sessions where gap > 30 min = new session, (4) top-N per group without subquery.", why: "Window functions are the most powerful analytical SQL feature. These patterns appear in data engineering and analytics interviews.", examples: "SELECT *, SUM(amount) OVER (PARTITION BY user_id ORDER BY date ROWS UNBOUNDED PRECEDING) as running_total", testInputs: "Island detection: LAG(date) to find where gap > threshold. Session: assign session_id using cumulative sum of gaps.", explanation: "ROWS vs RANGE: ROWS counts physical rows, RANGE groups equal values. Gap detection: row_number() - dense_rank() trick. Sessionization: cumulative sum of is_new_session flags using SUM() OVER ORDER BY." },
  { id: 5053, lang: "SQL", diff: "medium", title: "Index Design: Covering and Partial Indexes", concepts: "Composite Index, Index-Only Scan, Partial Index, GIN, INCLUDE", problem: "Design indexes for: (1) queries filtering on status + created_at + user_id, (2) a covering index that eliminates heap fetch using INCLUDE, (3) a partial index for only active records, (4) a GIN index for JSONB or array search.", why: "Index design is the #1 SQL performance topic in interviews. Wrong indexes cause 100x performance degradation.", examples: "CREATE INDEX CONCURRENTLY idx ON orders(user_id, created_at DESC) WHERE status='active' INCLUDE (amount)", testInputs: "EXPLAIN shows Index Only Scan => no heap access. Partial index size vs full index.", explanation: "Composite index: column order matters (high-selectivity first). INCLUDE columns allow index-only scans. Partial indexes reduce size and maintenance cost. GIN index supports array containment (@>) and full-text search." },
  { id: 5054, lang: "SQL", diff: "medium", title: "CTEs, Recursive Queries, and Materialization", concepts: "CTE, Materialization, WITH RECURSIVE, Hierarchy Traversal", problem: "Explain: (1) when CTEs are materialized vs inlined (PostgreSQL 12+ behavior change), (2) recursive CTE for hierarchy traversal (org chart, file system), (3) when to use a temp table instead of CTE for large intermediate results.", why: "CTE behavior differences across databases cause performance bugs. Recursive CTEs are a frequently tested senior topic.", examples: "WITH RECURSIVE org AS (SELECT * FROM employees WHERE manager_id IS NULL UNION ALL SELECT e.* FROM employees e JOIN org ON e.manager_id=org.id) SELECT * FROM org", testInputs: "Circular reference => infinite loop without cycle detection. Large hierarchy => compare CTE vs temp table performance.", explanation: "Pre-PG12: CTEs always materialized (optimization fence). PG12+: inlined by default. Recursive CTE: anchor + recursive term joined by UNION ALL. Add cycle detection or depth limit as safety guard." },
  { id: 5055, lang: "SQL", diff: "medium", title: "Normalization vs Denormalization and CQRS", concepts: "1NF/2NF/3NF, Denormalization, Materialized Views, CQRS, Write Amplification", problem: "Given a 3NF schema, explain when and how to denormalize for read performance. Cover: (1) materialized views as a denormalization strategy, (2) the write amplification cost, (3) CQRS pattern — separate read and write models.", why: "Normalization theory + practical denormalization tradeoffs is a senior-level topic that tests both theory and systems thinking.", examples: "3NF: orders -> order_items -> products. Denormalized: embed product name/price in order_items at write time.", testInputs: "Price change => 3NF: one update. Denormalized: update all historical order_items? Or accept historical snapshot?", explanation: "Denormalization: accept data redundancy for read speed. Materialized views auto-refresh. CQRS separates write model (normalized) from read model (denormalized). Historical snapshots are often the correct choice for order data." },
  { id: 5056, lang: "SQL", diff: "hard", title: "MVCC Internals: xmin/xmax and VACUUM", concepts: "MVCC, Snapshot Isolation, xmin/xmax, VACUUM, Dead Tuples, XID Wraparound", problem: "Explain PostgreSQL's MVCC implementation: (1) how each row stores xmin/xmax for visibility, (2) the 4 isolation levels and which read phenomena each prevents, (3) why VACUUM is needed and what happens without it (table bloat, XID wraparound), (4) HOT updates.", why: "MVCC internals differentiate staff engineers. XID wraparound is a real production disaster in PostgreSQL.", examples: "Dirty read => only READ UNCOMMITTED allows. Phantom read => SERIALIZABLE prevents. REPEATABLE READ prevents phantoms in PostgreSQL (but not SQL standard).", testInputs: "Long-running transaction => blocks VACUUM => table bloat. XID counter approaching 2^31 => emergency VACUUM FREEZE.", explanation: "MVCC: each row version has xmin (inserting transaction) and xmax (deleting transaction). Reader picks snapshot at transaction start. Dead tuples accumulate until VACUUM reclaims them. HOT: same-page updates avoid index maintenance." },
  { id: 5057, lang: "SQL", diff: "hard", title: "Table Partitioning Strategies", concepts: "Range/List/Hash Partition, Partition Pruning, Declarative Partitioning, Partition-wise Join", problem: "Design a partitioning strategy for a 10TB events table queried by date ranges. Explain: (1) declarative partitioning in PostgreSQL, (2) partition pruning and when it fails silently, (3) partition-wise joins and aggregates, (4) maintenance: adding partitions, detaching old ones.", why: "Partitioning is the primary strategy for managing very large tables. Partition pruning failing silently causes full table scans.", examples: "CREATE TABLE events PARTITION BY RANGE (event_date); CREATE TABLE events_2024_01 PARTITION OF events FOR VALUES FROM ('2024-01-01') TO ('2024-02-01');", testInputs: "EXPLAIN without WHERE on event_date => all partitions scanned. With WHERE => pruned to 1 partition.", explanation: "Range partition: date/numeric ranges. List: known set of values. Hash: even distribution for write scaling. Pruning only works if partition key is in WHERE clause without transformation (no functions on the column)." },
  { id: 5058, lang: "SQL", diff: "hard", title: "Anti-Joins, LATERAL, and NULL Pitfalls", concepts: "Anti-Join, Semi-Join, LATERAL, NOT IN vs NOT EXISTS, NULL semantics", problem: "Explain: (1) anti-join pattern and how NULLs silently break NOT IN, (2) LATERAL joins for correlated subqueries as table expressions, (3) why NOT EXISTS is safer and often faster than NOT IN for large subqueries.", why: "NOT IN with NULLs is a classic SQL bug that silently returns wrong results. LATERAL joins are powerful but rarely understood.", examples: "NOT IN bug: SELECT * FROM a WHERE id NOT IN (SELECT id FROM b) -- returns 0 rows if b has any NULL id", testInputs: "Add NULL to subquery in NOT IN => empty result set (wrong). Replace with NOT EXISTS => correct result.", explanation: "NOT IN: if subquery has NULL, result is always empty (NULL comparison returns UNKNOWN). NOT EXISTS: short-circuits correctly. LEFT JOIN + IS NULL: equivalent to NOT EXISTS. LATERAL: each row from left can reference right subquery per row." },
  { id: 5059, lang: "SQL", diff: "hard", title: "Deadlock Detection and Lock Patterns", concepts: "Lock Types, Deadlock, Lock Wait Graph, SELECT FOR UPDATE SKIP LOCKED, Advisory Locks", problem: "Explain: (1) how deadlocks occur in concurrent transactions and how PostgreSQL detects them, (2) prevention strategies: lock ordering, SELECT FOR UPDATE SKIP LOCKED for queue processing, advisory locks for application-level coordination.", why: "Deadlocks are a common production incident. Preventing them requires architectural knowledge of lock ordering.", examples: "T1: UPDATE WHERE id=1 then id=2. T2: UPDATE WHERE id=2 then id=1 => deadlock.", testInputs: "Reproduce deadlock => PostgreSQL auto-detects in ~1s (deadlock_timeout) and rolls back one transaction.", explanation: "Deadlock: circular wait on locks. PostgreSQL waits deadlock_timeout then checks for cycles. Prevention: always acquire locks in consistent order. SKIP LOCKED: queue processing pattern where multiple workers consume tasks without contention." },
  { id: 5060, lang: "SQL", diff: "hard", title: "JSONB Schema Design and GIN Indexing", concepts: "EAV Pattern, JSONB, GIN Index, Containment Operator, Partial Index", problem: "Compare EAV pattern vs JSONB for semi-structured product attributes. Implement with GIN indexes. Show how @> containment queries use indexes. Discuss tradeoffs vs a polymorphic schema.", why: "EAV vs JSONB is a real architectural decision. JSONB with GIN indexes achieves schema-flexibility with good query performance.", examples: "SELECT * FROM products WHERE attributes @> '{color: red}' AND (attributes->>'price')::numeric < 100", testInputs: "GIN index on attributes column. EXPLAIN shows Bitmap Index Scan. Compare with EAV JOIN query.", explanation: "EAV: flexible but JOIN-heavy, no type safety. JSONB: flexible, indexed, supports containment (@>), queryable with SQL. GIN with jsonb_path_ops operator class for containment queries. Use jsonb_ops for key existence queries." },
  { id: 5061, lang: "SQL", diff: "hard", title: "WAL, Replication Lag, and Read-Your-Writes", concepts: "Streaming Replication, WAL, Replication Lag, Sync vs Async, Read-Your-Writes", problem: "Explain: (1) how PostgreSQL streaming replication works (WAL shipping), (2) why replication lag causes read-your-writes consistency violations on replicas, (3) strategies: write to primary, sticky reads after write, or synchronous_commit.", why: "Replication lag is a common production bug in read-replica architectures. Understanding WAL is required for senior DB roles.", examples: "User updates profile => read from replica => sees old data. Fix: sticky sessions to primary for 1s after write.", testInputs: "pg_stat_replication shows replay_lsn < sent_lsn => replica is behind. Measure replication lag in bytes and milliseconds.", explanation: "WAL: Write-Ahead Log. Primary writes WAL, replica applies it. Async: primary doesn't wait for replica ack (fast, can lose data). synchronous_commit='remote_apply': strong consistency with higher write latency." },
  { id: 5062, lang: "SQL", diff: "hard", title: "Planner Statistics and Cardinality Estimation", concepts: "pg_stats, Histogram, NDV, Planner Cost Model, Statistics Target, Extended Statistics", problem: "Explain: (1) how the PostgreSQL planner uses column statistics (histogram, correlation, n_distinct) to estimate cardinality, (2) why stale statistics cause bad plans, (3) how to increase statistics_target for skewed columns, (4) Extended Statistics for correlated columns.", why: "Query planner misestimates are the root cause of most unexplained slow queries. Statistics knowledge is required for DBA-level performance debugging.", examples: "Column with skewed distribution => default 100 histogram buckets miss the peak. SET statistics=500 for better estimates.", testInputs: "EXPLAIN shows rows=1000 but actual rows=1000000 => statistics mismatch. Run ANALYZE then EXPLAIN => improved estimate.", explanation: "pg_stats stores: null_frac, n_distinct, histogram_bounds, correlation. Planner multiplies selectivities for AND conditions assuming independence (wrong for correlated columns). CREATE STATISTICS models correlations between columns." },
  { id: 5063, lang: "SQL", diff: "hard", title: "Temporal Data and SCD Type 2", concepts: "SCD Type 2, Bitemporal, tstzrange, Exclusion Constraints, Point-in-Time Query", problem: "Design a SCD Type 2 schema for product pricing history. Implement: (1) point-in-time queries ('what was the price on 2023-06-15?'), (2) bitemporal data (valid_time vs transaction_time), (3) PostgreSQL range types (tstzrange) with exclusion constraints for overlap prevention.", why: "Temporal data modeling is critical for auditing, analytics, and compliance. Range types with exclusion constraints are an advanced PostgreSQL feature.", examples: "CREATE TABLE prices (id, product_id, price, valid TSTZRANGE, EXCLUDE USING GIST (product_id WITH =, valid WITH &&))", testInputs: "Insert overlapping validity period => exclusion constraint violation. Query at past timestamp => correct historical price.", explanation: "SCD2: new row for each change with valid_from/valid_to. tstzrange: native range type with @>, &&, <@ operators. Exclusion constraint using GiST prevents overlapping ranges for same product. Bitemporal: valid_time (business truth) + transaction_time (when recorded)." },
  { id: 5064, lang: "SQL", diff: "hard", title: "Connection Pooling and N+1 Query Problem", concepts: "PgBouncer, Connection Overhead, N+1, Batch Loading, DataLoader Pattern", problem: "Explain: (1) why PostgreSQL connection overhead is high (per-process model), (2) how PgBouncer session/transaction/statement pooling modes work and their tradeoffs, (3) the N+1 query problem and how to fix it with JOINs or DataLoader batch-and-cache pattern.", why: "N+1 is the most common ORM performance bug. Connection pooling is required knowledge for any production backend engineer.", examples: "N+1: for each post, query comments => 1 + N queries. Fix: JOIN or IN clause for batch load.", testInputs: "100 users with 10 posts each => N+1 generates 101 queries. Batched => 2 queries. Measure latency difference.", explanation: "PostgreSQL spawns a process per connection (heavy). PgBouncer pools connections. Transaction mode: most efficient, connection released after each transaction. Statement mode: incompatible with prepared statements. DataLoader: batch keys within event loop tick, deduplicate, fetch once." }
];
